$y = f(|x|)$ denkleminin grafiği hangisidir?

[asy]
birim boyut(0,5 cm);

resim[]graf;
int i, n;

gerçek fonksiyon(gerçek x) {
  gerçek y;
  if (x >= -3 && x <= 0) {y = -2 - x;}
  if (x >= 0 && x <= 2) {y = sqrt(4 - (x - 2)^2) - 2;}
  if (x >= 2 && x <= 3) {y = 2*(x - 2);}
  dönüş(y);
}

gerçek funca(gerçek x) {
  return(func(abs(x)));
}

gerçek fonksiyon(gerçek x) {
  reel y = max(0,fonk(x));
  dönüş(y);
}

gerçek işlev(gerçek x) {
  return(abs(func(x)));
}

gerçek eğlence(gerçek x) {
  return(func(-abs(x)));
}

için (n = 1; n <= 5; ++n) {
  graf[n] = yeni resim;
  for (i = -5; i <= 5; ++i) {
    Draw(graf[n],(i,-5)--(i,5),gray(0.7));
    Draw(graf[n],(-5,i)--(5,i),gray(0.7));
  }
  çizim(graf[n],(-5,0)--(5,0),Oklar(6));
  çizim(graf[n],(0,-5)--(0,5),Oklar(6));

  label(graf[n],"$x$", (5,0), E);
  label(graf[n],"$y$", (0,5), N);
}

çizim(graf[1],grafik(funca,-3,3),kırmızı);
Draw(graf[2],graph(funcb,-3,3),red);
Draw(graf[3],reflect((0,0),(0,1))*graph(func,-3,3),red);
Draw(graf[4],graph(funcd,-3,3),red);
çizim(graf[5],grafik(işlev,-3,3),kırmızı);

label(graf[1], "A", (0,-6));
label(graf[2], "B", (0,-6));
label(graf[3], "C", (0,-6));
label(graf[4], "D", (0,-6));
label(graf[5], "E", (0,-6));

ekle(graf[1]);
add(shift((12,0))*(graf[2]));
add(shift((24,0))*(graf[3]));
add(shift((6,-12))*(graf[4]));
add(shift((18,-12))*(graf[5]));
[/asy]

